// ── Status messages ────────────────────────────────────────────────────────

const STATUS_MESSAGES: Record<ConnectionStatus, string> = {
  disconnected: "Device Not Connected",
  connecting: "Opening USB Device Picker…",
  authorizing: "Authorize on Phone Screen",
  connected: "Connected",
  error: "Device Disconnected",
};

